export function germanFoundationCardCopy(topicSlug, index, card = {}, conceptTitle = "") {
  const authored = GERMAN_FOUNDATION_CARD_COPY[topicSlug]?.[index];
  if (authored) return { plain: authored[0], trap: authored[1], authored: true };
  const example = card?.example || card?.title || "diesem Satz";
  return {
    plain: `Untersuche das Modell „${example}“ gezielt unter dem Blickwinkel „${conceptTitle || "dieses Satzmuster"}“. Achte darauf, welche Form die Bedeutung trägt und welches Detail du austauschen kannst.`,
    trap: "Lerne das Beispiel nicht als unteilbaren Block. Wenn du die tragende Form nicht erkennst, lässt sich das Muster später nur schwer auf einen neuen Satz übertragen.",
    authored: false
  };
}

export const germanFoundationCopyTopicSlugs = Object.freeze(Object.keys(GERMAN_FOUNDATION_CARD_COPY));
export const germanFoundationCopyCardCount = Object.freeze(Object.fromEntries(
  Object.entries(GERMAN_FOUNDATION_CARD_COPY).map(([slug, cards]) => [slug, cards.length])
));
